    public function fetch_markets($params = array()): PromiseInterface {
        return Async\async(function () use ($params) {
            /**
             * fetches binance prediction markets; with a query it resolves the query via the search endpoint and returns the matched topics' markets, otherwise it pages the market listing
             *
             * @see https://developers.binance.com/en/docs/catalog/web3-wallet-prediction-trading/api/rest-api/market-data
             *
             * @param {array} [$params] extra parameters specific to the exchange API endpoint
             * @param {string} [$params->query] a single search query resolved against the market search endpoint
             * @param {string[]} [$params->queries] multiple search $queries (alternative to query)
             * @param {string} [$params->l1Category] filter the listing by a level-1 category id (see the category/list endpoint)
             * @param {string} [$params->l2Category] filter the listing by a level-2 category id
             * @param {int} [$params->limit] for an unscoped listing (no query), the max number of topics to collect (defaults to options.maxFetchMarketsLimit, 200)
             * @return {array[]} an array of objects representing market data
             */
            $queries = $this->parse_search_queries($params);
            $queriesLength = count($queries);
            if ($queriesLength > 0) {
                $eventParams = $this->omit($params, array( 'limit' ));
                $events = Async\await($this->fetch_events($eventParams));
                $eventsLength = count($events);
                $queryMarkets = array();
                for ($ei = 0; $ei < $eventsLength; $ei++) {
                    $eventMarkets = $this->safe_list($events[$ei], 'markets', array());
                    $eventMarketsLength = count($eventMarkets);
                    for ($mi = 0; $mi < $eventMarketsLength; $mi++) {
                        $queryMarkets[] = $eventMarkets[$mi];
                    }
                }
                return $queryMarkets;
            }
            $maxMarkets = $this->safe_integer($params, 'limit', $this->safe_integer($this->options, 'maxFetchMarketsLimit', 200));
            $rest = $this->omit($params, array( 'query', 'queries', 'limit' ));
            $rawTopics = Async\await($this->fetch_raw_topics($maxMarkets, $rest));
            $parsedEvents = array();
            $flatMarkets = array();
            $rawTopicsLength = count($rawTopics);
            for ($i = 0; $i < $rawTopicsLength; $i++) {
                $parsedEvent = $this->parse_event($rawTopics[$i]);
                $parsedEvents[] = $parsedEvent;
                $eventMarkets = $this->safe_list($parsedEvent, 'markets', array());
                $eventMarketsLength = count($eventMarkets);
                for ($mi = 0; $mi < $eventMarketsLength; $mi++) {
                    $flatMarkets[] = $eventMarkets[$mi];
                }
            }
            $this->set_events($parsedEvents);
            return $flatMarkets;
        })();
    }

    public function fetch_raw_topics(?int $maxTopics, $rest = array()): PromiseInterface {
        return Async\async(function () use ($maxTopics, $rest) {
            /**
             * @ignore
             * pages the market/list endpoint and returns up to `$maxTopics` raw market topics
             * @param {int} $maxTopics stop collecting once this many topics are gathered
             * @param {array} [$rest] extra params forwarded verbatim to the listing endpoint (l1Category, l2Category, sortBy, orderBy)
             * @return {array[]} raw market topic objects
             */
            $pageLimit = $this->safe_integer($this->options, 'marketsPageLimit', 100);
            $collected = array();
            $offset = 0;
            while (true) {
                $reqLimit = $pageLimit;
                $collectedLength = count($collected);
                $remaining = $maxTopics - $collectedLength;
                if ($remaining < $reqLimit) {
                    $reqLimit = $remaining;
                }
                if ($reqLimit <= 0) {
                    break;
                }
                $request = array(
                    'offset' => $offset,
                    'limit' => $reqLimit,
                );
                $response = Async\await($this->sapiPrivateGetMarketList($this->extend($request, $rest)));
                //
                //     {
                //         "marketTopics" => array(
                //             {
                //                 "marketTopicId" => 4229564,
                //                 "vendor" => "PREDICT_FUN",
                //                 "chainId" => "56",
                //                 "slug" => "btc-price-1h-up-or-down",
                //                 "title" => "BTC Price 1h Up or Down?",
                //                 "question" => "Will BTC price go UP?",
                //                 "topicType" => "FLAT",
                //                 "chartType" => "CRYPTO_UP_DOWN",
                //                 "symbol" => "BTCUSDT",
                //                 "participantCount" => 3420,
                //                 "collateral" => "USDT",
                //                 "feeRateBps" => 200,
                //                 "slippageBps" => 1200,
                //                 "tradeVolume" => "158234.56",
                //                 "liquidity" => "45000.00",
                //                 "publishedAt" => 1748100000000,
                //                 "startDate" => 1748131200000,
                //                 "endDate" => 1748134800000,
                //                 "status" => "REGISTERED",
                //                 "markets" => array()
                //             }
                //         ),
                //         "total" => 128,
                //         "offset" => 0,
                //         "limit" => 20,
                //         "hasMore" => true
                //     }
                //
                $pageTopics = $this->safe_list($response, 'marketTopics', array());
                $pageTopicsLength = count($pageTopics);
                for ($i = 0; $i < $pageTopicsLength; $i++) {
                    $collected[] = $pageTopics[$i];
                }
                $hasMore = $this->safe_bool($response, 'hasMore', false);
                if (!$hasMore || ($pageTopicsLength < $reqLimit)) {
                    break;
                }
                $offset = $this->sum($offset, $pageTopicsLength);
            }
            return $collected;
        })();
    }

