    public function complete_raw_topics(array $rawTopics): PromiseInterface {
        return Async\async(function () use ($rawTopics) {
            /**
             * @ignore
             * ensures each raw topic carries fully-populated nested markets (with outcome token ids), fetching the topic $detail when the listing/search payload omitted them
             * @param {array[]} $rawTopics raw market topic objects
             * @return {array[]} raw market topic objects with usable nested markets
             */
            $result = array();
            $rawTopicsLength = count($rawTopics);
            for ($i = 0; $i < $rawTopicsLength; $i++) {
                $rawTopic = $rawTopics[$i];
                $rawMarkets = $this->safe_list($rawTopic, 'markets', array());
                $rawMarketsLength = count($rawMarkets);
                $hasOutcomes = false;
                if ($rawMarketsLength > 0) {
                    $firstMarket = $this->safe_dict($rawMarkets, 0, array());
                    $firstOutcomes = $this->safe_list($firstMarket, 'outcomes', array());
                    $firstOutcomesLength = count($firstOutcomes);
                    $hasOutcomes = ($firstOutcomesLength > 0);
                }
                if ($hasOutcomes) {
                    $result[] = $rawTopic;
                } else {
                    $topicId = $this->safe_string($rawTopic, 'marketTopicId');
                    if ($topicId !== null) {
                        $detail = Async\await($this->fetch_raw_topic_detail($topicId));
                        $result[] = $detail;
                    }
                }
            }
            return $result;
        })();
    }

    public function fetch_events(array $params = array()): PromiseInterface {
        return Async\async(function () use ($params) {
            /**
             * fetches prediction-market events (market topics); the call must be scoped by query/queries/tags, $eventId, or an l1Category/l2Category listing filter
             *
             * @see https://developers.binance.com/en/docs/catalog/web3-wallet-prediction-trading/api/rest-api/market-data
             *
             * @param {array} [$params] extra parameters specific to the exchange API endpoint
             * @param {string} [$params->query] a free-text search resolved against the semantic market search endpoint
             * @param {string[]} [$params->queries] multiple free-text searches (alternative to query)
             * @param {string[]} [$params->tags] treated free-text searches (binance has no tag taxonomy)
             * @param {string} [$params->eventId] a marketTopicId, fetched directly via the $detail endpoint
             * @param {string} [$params->l1Category] scope the listing server-side by a level-1 category id
             * @param {string} [$params->l2Category] scope the listing server-side by a level-2 category id
             * @param {int} [$params->limit] the maximum number of events to return
             * @param {string} [$params->sort] 'volume' | 'liquidity' | 'newest' (client-side)
             * @param {string} [$params->status] 'active' | 'closed' | 'all' (client-side)
             * @return {array[]} a list of [prediction event structures](https://docs.ccxt.com/#/?id=prediction-event-structure)
             */
            $this->require_event_query($params);
            $queries = $this->parse_search_queries($params);
            // binance has no tag taxonomy — resolve requested $tags through the semantic search too
            $tags = $this->safe_list($params, 'tags', array());
            $tagsLength = count($tags);
            $allQueries = array();
            for ($i = 0; $i < count($queries); $i++) {
                $allQueries[] = $queries[$i];
            }
            for ($i = 0; $i < $tagsLength; $i++) {
                $allQueries[] = $tags[$i];
            }
            $allQueriesLength = count($allQueries);
            $params = $this->omit($params, array( 'query', 'queries' ));
            $userLimit = $this->safe_integer($params, 'limit');
            $fetchCap = $this->safe_integer($this->options, 'maxFetchEventsResults', 25);
            if ($userLimit !== null) {
                $fetchCap = $userLimit;
            }
            $rest = $this->omit($params, array( 'status', 'limit', 'sort', 'searchIn', 'eventId', 'slug', 'tags', 'l1Category', 'l2Category' ));
            $eventId = $this->safe_string_2($params, 'eventId', 'slug');
            $l1Category = $this->safe_string($params, 'l1Category');
            $l2Category = $this->safe_string($params, 'l2Category');
            if (!$this->markets) {
                $this->markets = $this->create_safe_dictionary();
            }
            $rawTopics = array();
            if ($allQueriesLength > 0) {
                $rawTopics = Async\await($this->fetch_events_by_query($allQueries, $fetchCap, $rest));
            } elseif ($eventId !== null) {
                $detail = Async\await($this->fetch_raw_topic_detail($eventId, $rest));
                $rawTopics = array( $detail );
            } else {
                $listingRequest = array();
                if ($l1Category !== null) {
                    $listingRequest['l1Category'] = $l1Category;
                }
                if ($l2Category !== null) {
                    $listingRequest['l2Category'] = $l2Category;
                }
                $listed = Async\await($this->fetch_raw_topics($fetchCap, $this->extend($listingRequest, $rest)));
                $rawTopics = Async\await($this->complete_raw_topics($listed));
            }
            $rawTopicsLength = count($rawTopics);
            $result = array();
            for ($i = 0; $i < $rawTopicsLength; $i++) {
                $parsedEvent = $this->parse_event($rawTopics[$i]);
                $result[] = $parsedEvent;
                $parsedMarkets = $this->safe_list($parsedEvent, 'markets', array());
                $parsedMarketsLength = count($parsedMarkets);
                for ($mi = 0; $mi < $parsedMarketsLength; $mi++) {
                    $m = $parsedMarkets[$mi];
                    $this->markets[$m['market']] = $m;
                }
            }
            $this->populate_outcomes();
            // scoping already happened server-side => the tag filter needs an event-level $tags field
            // binance topics lack, and the query filter would drop semantic-search matches whose
            // title uses different words than the query
            $postParams = $this->omit($params, array( 'tags', 'l1Category', 'l2Category' ));
            return $this->apply_event_fetch_params($result, $postParams, array());
        })();
    }

    public function fetch_events_by_query(array $queries, ?int $limit, $rest = array()): PromiseInterface {
        return Async\async(function () use ($queries, $limit, $rest) {
            /**
             * @ignore
             * resolves free-text $queries through the semantic market search endpoint, then completes the matched topics with their outcome tokens
             * @param {string[]} $queries free-text search strings
             * @param {int} [$limit] max number of topics to fetch
             * @param {array} [$rest] extra params forwarded verbatim to the search endpoint
             * @return {array[]} raw market topic objects with usable nested markets
             */
            $seen = array();
            $collected = array();
            $queriesLength = count($queries);
            for ($qi = 0; $qi < $queriesLength; $qi++) {
                $request = array(
                    'query' => $queries[$qi],
                );
                if ($limit !== null) {
                    $request['topK'] = $limit;
                }
                $response = Async\await($this->sapiPrivateGetMarketSearch($this->extend($request, $rest)));
                //
                //     array(
                //         {
                //             "marketTopicId" => 4229564,
                //             "vendor" => "PREDICT_FUN",
                //             "slug" => "btc-price-1h-up-or-down",
                //             "title" => "BTC Price 1h Up or Down?",
                //             ...
                //             "markets" => array()
                //         }
                //     )
                //
                $responseLength = count($response);
                for ($i = 0; $i < $responseLength; $i++) {
                    $rawTopic = $response[$i];
                    $topicId = $this->safe_string($rawTopic, 'marketTopicId');
                    if ($topicId !== null) {
                        $already = $this->safe_string($seen, $topicId);
                        if ($already === null) {
                            $seen[$topicId] = $topicId;
                            $collected[] = $rawTopic;
                        }
                    }
                }
            }
            $capped = $collected;
            $collectedLength = count($collected);
            if (($limit !== null) && ($collectedLength > $limit)) {
                $capped = $this->array_slice($collected, 0, $limit);
            }
            return Async\await($this->complete_raw_topics($capped));
        })();
    }

    public function fetch_event(string $id, $params = array()): PromiseInterface {
        return Async\async(function () use ($id, $params) {
            /**
             * fetches a single prediction-market $event (market topic) by its marketTopicId
             *
             * @see https://developers.binance.com/en/docs/catalog/web3-wallet-prediction-trading/api/rest-api/market-data
             *
             * @param {string} $id the marketTopicId
             * @param {array} [$params] extra parameters specific to the exchange API endpoint
             * @return {array} a [prediction $event structure](https://docs.ccxt.com/#/?$id=prediction-$event-structure)
             */
            $detail = Async\await($this->fetch_raw_topic_detail($id, $params));
            $event = $this->parse_event($detail);
            $this->index_event_outcomes($event);
            return $event;
        })();
    }

    public function parse_event(array $rawTopic): mixed {
        /**
         * @ignore
         * parses a raw binance market topic (with nested markets) into the unified event shape
         * @param {array} $rawTopic the raw market topic object
         * @return {array} an event structure
         */
        //
        //     {
        //         "marketTopicId" => 4229564,
        //         "vendor" => "PREDICT_FUN",
        //         "chainId" => "56",
        //         "slug" => "btc-price-1h-up-or-down",
        //         "title" => "BTC Price 1h Up or Down?",
        //         "question" => "Will BTC price go UP?",
        //         "description" => "Resolves YES if BTC spot price is higher than the starting price.",
        //         "imageUrl" => "https://...",
        //         "topicType" => "FLAT",
        //         "chartType" => "CRYPTO_UP_DOWN",
        //         "symbol" => "BTCUSDT",
        //         "variantData" => array( "type" => "CRYPTO_UP_DOWN", "startPrice" => "67890.12", "endPrice" => null ),
        //         "participantCount" => 3420,
        //         "collateral" => "USDT",
        //         "feeRateBps" => 200,
        //         "slippageBps" => 1200,
        //         "tradeVolume" => "158234.56",
        //         "liquidity" => "45000.00",
        //         "publishedAt" => 1748100000000,
        //         "startDate" => 1748131200000,
        //         "endDate" => 1748134800000,
        //         "status" => "REGISTERED",
        //         "timeline" => array( ... ),
        //         "markets" => array( array( "marketId" => 5567895, "title" => "UP", "outcomes" => array( ... ) ) )
        //     }
        //
        $rawMarkets = $this->safe_list($rawTopic, 'markets', array());
        $marketsList = array();
        $anyActive = false;
        $rawMarketsLength = count($rawMarkets);
        for ($i = 0; $i < $rawMarketsLength; $i++) {
            $parsed = $this->parse_topic_market($rawMarkets[$i], $rawTopic);
            $marketsList[] = $parsed;
            if ($this->safe_bool($parsed, 'active', false)) {
                $anyActive = true;
            }
        }
        $topicId = $this->safe_string($rawTopic, 'marketTopicId');
        $slug = $this->safe_string($rawTopic, 'slug');
        $title = $this->safe_string($rawTopic, 'title');
        $endDate = $this->safe_integer($rawTopic, 'endDate');
        $created = $this->safe_integer_2($rawTopic, 'publishedAt', 'startDate');
        $active = $anyActive;
        if ($rawMarketsLength === 0) {
            $status = $this->safe_string($rawTopic, 'status');
            $active = ($status === 'REGISTERED') || ($status === 'OPEN');
        }
        return array(
            'id' => $topicId,
            'slug' => $slug,
            'event' => ($slug !== null) ? $this->shorten_slug($slug) : null,
            'title' => $title,
            'description' => $this->safe_string($rawTopic, 'description'),
            'markets' => $marketsList,
            'active' => $active,
            'volume' => $this->safe_number($rawTopic, 'tradeVolume'),
            'liquidity' => $this->safe_number($rawTopic, 'liquidity'),
            'url' => null,
            'image' => $this->safe_string($rawTopic, 'imageUrl'),
            'created' => $created,
            'createdDatetime' => $this->iso8601($created),
            'end' => $endDate,
            'endDatetime' => $this->iso8601($endDate),
            'category' => $this->safe_string($rawTopic, 'chartType'),
            'resolved' => null,
            'info' => $rawTopic,
        );
    }

    public function parse_topic_market(array $rawMarket, array $rawTopic): array {
        /**
         * @ignore
         * parses one nested market of a market topic into the unified market shape, building its outcome tokens
         * @param {array} $rawMarket the nested market object
         * @param {array} $rawTopic the enclosing raw market topic (carries slug/vendor/fees/dates)
         * @return {array} a market structure
         */
        //
        //     {
        //         "marketId" => 5567895,
        //         "externalId" => "ext_001",
        //         "title" => "UP",
        //         "question" => "Will BTC go UP?",
        //         "description" => "Resolves YES if BTC $price increases.",
        //         "conditionId" => "0xabc123",
        //         "status" => "REGISTERED",
        //         "tradingStatus" => "OPEN",
        //         "tradeVolume" => "90000.00",
        //         "liquidity" => "25000.00",
        //         "decimalPrecision" => 2,
        //         "outcomes" => array(
        //             array( "name" => "YES", "price" => "0.52", "chance" => "0.52", "index" => 0, "tokenId" => "112233" )
        //         )
        //     }
        //
        $marketId = $this->safe_string($rawMarket, 'marketId');
        $topicId = $this->safe_string($rawTopic, 'marketTopicId');
        $topicSlug = $this->safe_string($rawTopic, 'slug');
        $vendor = $this->safe_string($rawTopic, 'vendor');
        $collateral = $this->safe_string($rawTopic, 'collateral', 'USDT');
        $title = $this->safe_string($rawMarket, 'title', $marketId);
        $marketSymbol = $this->slug_to_market_symbol($topicSlug, $title);
        $tradingStatus = $this->safe_string($rawMarket, 'tradingStatus');
        $status = $this->safe_string($rawMarket, 'status');
        $active = ($tradingStatus === 'OPEN');
        if ($tradingStatus === null) {
            $active = ($status === 'REGISTERED') || ($status === 'OPEN');
        }
        $resolved = ($status === 'RESOLVED') || ($status === 'SETTLED');
        $endDate = $this->safe_integer($rawTopic, 'endDate');
        $feeRateBps = $this->safe_string($rawTopic, 'feeRateBps', '200');
        $feeRate = $this->parse_number(Precise::string_div($feeRateBps, '10000'));
        $decimalPrecision = $this->safe_string($rawMarket, 'decimalPrecision', '2');
        $pricePrecision = $this->parse_number($this->parse_precision($decimalPrecision));
        $precision = array(
            'amount' => null,
            'price' => $pricePrecision,
        );
        $volume = $this->safe_number($rawMarket, 'tradeVolume');
        $liquidity = $this->safe_number($rawMarket, 'liquidity');
        $rawOutcomes = $this->safe_list($rawMarket, 'outcomes', array());
        $outcomes = array();
        $resolvedOutcomeRaw = null;
        $rawOutcomesLength = count($rawOutcomes);
        for ($oi = 0; $oi < $rawOutcomesLength; $oi++) {
            $rawOutcome = $rawOutcomes[$oi];
            $label = $this->safe_string_upper($rawOutcome, 'name');
            $tokenId = $this->safe_string($rawOutcome, 'tokenId');
            $outcomeHandle = $this->slug_to_outcome_symbol($topicSlug, $title, $label);
            $price = $this->safe_string($rawOutcome, 'price');
            $winnerRaw = null;
            $settleFractionRaw = null;
            if ($resolved && ($price !== null)) {
                $winnerRaw = Precise::string_eq($price, '1');
                $settleFractionRaw = ($winnerRaw) ? 1 : 0;
                if ($winnerRaw) {
                    $resolvedOutcomeRaw = $outcomeHandle;
                }
            }
            $winner = $winnerRaw;
            $settleFraction = $settleFractionRaw;
            $outcomes[] = array(
                'id' => $tokenId,
                'outcomeId' => $tokenId,
                'outcome' => $outcomeHandle,
                'market' => $marketSymbol,
                'label' => $label,
                'active' => $active,
                'winner' => $winner,
                'settleFraction' => $settleFraction,
                'precision' => $precision,
                'info' => array(
                    'tokenId' => $tokenId,
                    'marketId' => $marketId,
                    'marketTopicId' => $topicId,
                    'vendor' => $vendor,
                    'chainId' => $this->safe_string($rawTopic, 'chainId'),
                    'slug' => $topicSlug,
                    'marketTitle' => $title,
                    'outcomeLabel' => $label,
                    'index' => $this->safe_string($rawOutcome, 'index'),
                    'price' => $price,
                    'chance' => $this->safe_string($rawOutcome, 'chance'),
                    'collateral' => $collateral,
                    'feeRateBps' => $feeRateBps,
                    'slippageBps' => $this->safe_string($rawTopic, 'slippageBps'),
                    'conditionId' => $this->safe_string($rawMarket, 'conditionId'),
                    'externalId' => $this->safe_string($rawMarket, 'externalId'),
                ),
            );
        }
        $resolvedOutcome = $resolvedOutcomeRaw;
        return array(
            'id' => $marketId,
            'market' => $marketSymbol,
            'base' => $collateral,
            'quote' => $collateral,
            'settle' => null,
            'baseId' => $marketId,
            'quoteId' => $collateral,
            'settleId' => null,
            'type' => 'prediction',
            'marketType' => 'binary',
            'executionModel' => 'clob',
            'spot' => false,
            'margin' => false,
            'swap' => false,
            'future' => false,
            'option' => false,
            'prediction' => true,
            'active' => $active,
            'resolved' => $resolved,
            'resolvedOutcome' => $resolvedOutcome,
            'contract' => false,
            'linear' => null,
            'inverse' => null,
            'contractSize' => null,
            'expiry' => $endDate,
            'expiryDatetime' => $this->iso8601($endDate),
            'strike' => null,
            'optionType' => null,
            'taker' => $feeRate,
            'maker' => $feeRate,
            'percentage' => true,
            'tierBased' => false,
            'feeSide' => 'get',
            'precision' => $precision,
            'limits' => array(
                'leverage' => array( 'min' => 1, 'max' => 1 ),
                'amount' => array( 'min' => null, 'max' => null ),
                'price' => array( 'min' => 0.01, 'max' => 0.99 ),
                'cost' => array( 'min' => 1.5, 'max' => null ),  // MARKET quotes require amountIn of at least ~1.5 USDT
            ),
            'outcomes' => $outcomes,
            'info' => $this->extend($rawMarket, array(
                'marketTopicId' => $topicId,
                'vendor' => $vendor,
                'slug' => $topicSlug,
                'volume' => $volume,
                'liquidity' => $liquidity,
            )),
            'created' => $this->safe_integer($rawTopic, 'publishedAt'),
        );
    }

    public function fetch_ticker(?string $outcome, $params = array()): PromiseInterface {
        return Async\async(function () use ($outcome, $params) {
            /**
             * fetches the last trade price for a single prediction $outcome
             *
             * @see https://developers.binance.com/en/docs/catalog/web3-wallet-prediction-trading/api/rest-api/market-data
             *
             * @param {string} $outcome unified $outcome handle like BTC_PRICE_1H_UP_DOWN_UP:YES, or an $outcome token id
             * @param {array} [$params] extra parameters specific to the exchange API endpoint
             * @return {array} a prediction [ticker structure](https://docs.ccxt.com/#/?id=ticker-structure)
             */
            Async\await($this->load_outcome($outcome));
            $outcomeObj = $this->outcome($outcome);
            $info = $this->safe_dict($outcomeObj, 'info', array());
            $request = array(
                'marketId' => $this->safe_string($info, 'marketId'),
            );
            $response = Async\await($this->sapiPrivateGetOrderBookLastTradePrice($this->extend($request, $params)));
            //
            //     array( "marketId" => 5567895, "lastTradePrice" => "0.52" )
            //
            return $this->parse_prediction_ticker($response, $outcomeObj);
        })();
    }

    public function parse_prediction_ticker(array $raw, ?array $market = null): array {
        /**
         * @ignore
         * parses a $last-trade-price response into a unified ticker object; the venue quotes the market's primary (YES) token, so a NO outcome mirrors - price
         * @param {array} $raw the $raw $last-trade-price object
         * @param {array} [$market] the outcome object the ticker belongs to
         * @return {array} a [ticker structure](https://docs.ccxt.com/#/?id=ticker-structure)
         */
        //
        //     array( "marketId" => 5567895, "lastTradePrice" => "0.52" )
        //
        $marketAny = $market;
        $outcomeObj = $this->safe_outcome($this->safe_string($marketAny, 'outcome'), $marketAny);
        $label = $this->safe_string_upper($outcomeObj, 'label', 'YES');
        $isNo = ($label === 'NO');
        $lastString = $this->safe_string($raw, 'lastTradePrice');
        $last = null;
        if ($lastString !== null) {
            if ($isNo) {
                $last = $this->parse_number(Precise::string_sub('1', $lastString));
            } else {
                $last = $this->parse_number($lastString);
            }
        }
        $now = $this->milliseconds();
        return $this->safe_prediction_ticker(array(
            'outcome' => $this->safe_string($outcomeObj, 'outcome'),
            'outcomeId' => $this->safe_string_2($outcomeObj, 'outcomeId', 'id'),
            'label' => $this->safe_string($outcomeObj, 'label'),
            'market' => $this->safe_string($outcomeObj, 'market'),
            'timestamp' => $now,
            'datetime' => $this->iso8601($now),
            'high' => null,
            'low' => null,
            'bid' => null,
            'bidVolume' => null,
            'ask' => null,
            'askVolume' => null,
            'vwap' => null,
            'open' => null,
            'close' => $last,
            'last' => $last,
            'previousClose' => null,
            'change' => null,
            'percentage' => null,
            'average' => null,
            'baseVolume' => null,
            'quoteVolume' => null,
            'info' => $raw,
        ), $market);
    }

    public function fetch_tickers(?array $outcomes = null, $params = array()): PromiseInterface {
        return Async\async(function () use ($outcomes, $params) {
            /**
             * fetches last trade prices for multiple $outcomes, one $request per distinct underlying market
             *
             * @see https://developers.binance.com/en/docs/catalog/web3-wallet-prediction-trading/api/rest-api/market-data
             *
             * @param {string[]} $outcomes unified $outcomes — required => the venue has no all-tickers endpoint
             * @param {array} [$params] extra parameters specific to the exchange API endpoint
             * @return {array} a dictionary of prediction [$ticker structures](https://docs.ccxt.com/#/?id=$ticker-structure)
             */
            if ($outcomes === null) {
                throw new ArgumentsRequired($this->id . ' fetchTickers() requires an $outcomes argument — the venue has no all-tickers endpoint; pass the outcome handles to fetch (discover them via fetchEvents ())');
            }
            Async\await($this->load_outcomes($outcomes));
            $responsesByMarketId = array();
            $result = array();
            $outcomesLength = count($outcomes);
            for ($i = 0; $i < $outcomesLength; $i++) {
                $outcomeObj = $this->outcome($outcomes[$i]);
                $info = $this->safe_dict($outcomeObj, 'info', array());
                $marketId = $this->safe_string($info, 'marketId');
                if ($marketId === null) {
                    continue;
                }
                $response = $this->safe_dict($responsesByMarketId, $marketId);
                if ($response === null) {
                    $request = array(
                        'marketId' => $marketId,
                    );
                    $response = Async\await($this->sapiPrivateGetOrderBookLastTradePrice($this->extend($request, $params)));
                    $responsesByMarketId[$marketId] = $response;
                }
                $ticker = $this->parse_prediction_ticker($response, $outcomeObj);
                $symbolKey = $this->safe_string($ticker, 'outcome', $outcomes[$i]);
                $result[$symbolKey] = $ticker;
            }
            return $result;
        })();
    }

    public function fetch_order_book(?string $outcome, ?int $limit = null, $params = array()): PromiseInterface {
        return Async\async(function () use ($outcome, $limit, $params) {
            /**
             * fetches the order book for a single prediction $outcome token
             *
             * @see https://developers.binance.com/en/docs/catalog/web3-wallet-prediction-trading/api/rest-api/market-data
             *
             * @param {string} $outcome unified $outcome handle, or an $outcome token id
             * @param {int} [$limit] not used by binance fetchOrderBook
             * @param {array} [$params] extra parameters specific to the exchange API endpoint
             * @return {array} a prediction [order book structure](https://docs.ccxt.com/#/?id=order-book-structure)
             */
            Async\await($this->load_outcome($outcome));
            $outcomeObj = $this->outcome($outcome);
            $info = $this->safe_dict($outcomeObj, 'info', array());
            $request = array(
                'vendor' => $this->safe_string($info, 'vendor', $this->safe_string($this->options, 'defaultVendor')),
                'marketId' => $this->safe_string($info, 'marketId'),
                'tokenId' => $this->safe_string_2($outcomeObj, 'outcomeId', 'id'),
            );
            $response = Async\await($this->sapiPrivateGetOrderBook($this->extend($request, $params)));
            //
            //     {
            //         "outcome" => "YES",
            //         "tokenId" => "112233",
            //         "timestamp" => 1748131800000,
            //         "bids" => array( array( "price" => "0.51", "size" => "5000.00" ) ),
            //         "asks" => array( array( "price" => "0.52", "size" => "3000.00" ) )
            //     }
            //
            $timestamp = $this->safe_integer($response, 'timestamp');
            $orderbook = $this->parse_order_book($response, $this->safe_outcome_symbol($outcome, $outcomeObj), $timestamp, 'bids', 'asks', 'price', 'size');
            return $this->safe_prediction_order_book($orderbook, $outcomeObj);
        })();
    }

    public function handle_errors(int $code, string $reason, string $url, string $method, array $headers, string $body, mixed $response, mixed $requestHeaders, mixed $requestBody) {
        if ($response === null) {
            return null;
        }
        $errorCode = $this->safe_string($response, 'code');
        if (($errorCode !== null) && Precise::string_lt($errorCode, '0')) {
            $message = $this->safe_string($response, 'msg', '');
            $feedback = $this->id . ' ' . $body;
            $this->throw_exactly_matched_exception($this->exceptions['exact'], $errorCode, $feedback);
            $this->throw_broadly_matched_exception($this->exceptions['broad'], $message, $feedback);
            throw new ExchangeError($feedback);
        }
        return null;
    }

    public function sign(mixed $path, mixed $api = 'sapi', $method = 'GET', $params = array(), mixed $headers = null, mixed $body = null) {
        /**
         * @ignore
         * builds the request URL and attaches the standard binance SAPI HMAC-SHA256 $signature — every prediction endpoint is signed
         * @param {string} $path the endpoint $path
         * @param {string|string[]} [$api] the $api group and access level
         * @param {string} [$method] HTTP $method
         * @param {array} [$params] request parameters
         * @param {array} [$headers] request $headers
         * @param {array} [$body] request $body
         * @return {array} a dictionary with $url, $method, $body and $headers
         */
        $apiGroup = gettype($api) === 'string' ? $api : $api[0];
        $baseUrls = $this->urls['api'];
        $baseUrl = $this->safe_string($baseUrls, $apiGroup, $baseUrls['sapi']);
        $url = $baseUrl . '/' . $this->implode_params($path, $params);
        $query = $this->omit($params, $this->extract_params($path));
        $this->check_required_credentials();
        $extendedParams = $this->extend(array(
            'timestamp' => $this->nonce(),
        ), $query);
        $defaultRecvWindow = $this->safe_integer($this->options, 'recvWindow');
        if ($defaultRecvWindow !== null) {
            $extendedParams['recvWindow'] = $defaultRecvWindow;
        }
        $querystring = $this->urlencode($extendedParams);
        $signature = $this->hmac($this->encode($querystring), $this->encode($this->secret), 'sha256');
        $querystring = $querystring . '&$signature=' . $signature;
        $headers = array(
            'X-MBX-APIKEY' => $this->apiKey,
        );
        if (($method === 'GET') || ($method === 'DELETE')) {
            $url = $url . '?' . $querystring;
        } else {
            $body = $querystring;
            $headers['Content-Type'] = 'application/x-www-form-urlencoded';
        }
        return array( 'url' => $url, 'method' => $method, 'body' => $body, 'headers' => $headers );
    }
}
